<script setup lang="ts">
import {computed, onMounted, ref} from "vue"
import type {BusinessAvailabilityRuleRequestDTO, BusinessAvailabilityRuleResponseDTO, BusinessOfferingResponseDTO} from "../../../contracts/index.ts"
import {userShellApi} from "../api/userShellApi.ts"
import AppDialog from "../components/AppDialog.vue"
import AppButton from "../components/AppButton.vue"
import AppFormField from "../components/AppFormField.vue"
import AppFormFooter from "../components/AppFormFooter.vue"
import AppStatus from "../components/AppStatus.vue"
import CollectionToolbar from "../components/CollectionToolbar.vue"
import SurfaceRow from "../components/SurfaceRow.vue"
import {confirmAction} from "../composables/useActionDialog.ts"

const rules = ref<BusinessAvailabilityRuleResponseDTO[]>([])
const offerings = ref<BusinessOfferingResponseDTO[]>([])
const form = ref<BusinessAvailabilityRuleRequestDTO | null>(null)
const editingId = ref<number | null>(null)
const isLoading = ref(true)
const isSaving = ref(false)
const error = ref("")
const feedback = ref("")
const selectedRuleId = ref<number | null>(null)
const selectedRule = computed(() => rules.value.find((rule) => rule.id === selectedRuleId.value) ?? null)
const days = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"]
const today = () => new Date().toISOString().slice(0, 10)
const emptyForm = (): BusinessAvailabilityRuleRequestDTO => ({businessOfferingId: offerings.value[0]?.id ?? 0, dayOfWeek: 1, startTimeLocal: "09:00", endTimeLocal: "17:00", slotGranularityMinutes: 60, capacityOverride: 1, validFrom: today(), validUntil: "", active: true})
const load = async () => { isLoading.value = true; error.value = ""; try { const [ruleResponse, offeringResponse] = await Promise.all([userShellApi.getBusinessAvailabilityRules(), userShellApi.getBusinessOfferings()]); rules.value = ruleResponse.items; offerings.value = offeringResponse.items } catch { error.value = "Could not load availability." } finally { isLoading.value = false } }
const beginCreate = () => { editingId.value = null; form.value = emptyForm(); feedback.value = "" }
const beginEdit = (rule: BusinessAvailabilityRuleResponseDTO) => { editingId.value = rule.id; form.value = {businessOfferingId: rule.businessOfferingId, dayOfWeek: rule.dayOfWeek, startTimeLocal: rule.startTimeLocal, endTimeLocal: rule.endTimeLocal, slotGranularityMinutes: rule.slotGranularityMinutes, capacityOverride: rule.capacityOverride, validFrom: rule.validFrom, validUntil: rule.validUntil, active: rule.active}; feedback.value = "" }
const save = async () => { if (!form.value || !form.value.businessOfferingId) return; isSaving.value = true; error.value = ""; try { if (editingId.value) await userShellApi.updateBusinessAvailabilityRule(editingId.value, form.value); else await userShellApi.createBusinessAvailabilityRule(form.value); form.value = null; feedback.value = "Availability rule saved."; await load() } catch { error.value = "Could not save this availability rule." } finally { isSaving.value = false } }
const remove = async (rule: BusinessAvailabilityRuleResponseDTO) => { if (!await confirmAction("Delete this availability rule?", "Delete availability rule")) return; isSaving.value = true; error.value = ""; try { await userShellApi.deleteBusinessAvailabilityRule(rule.id); feedback.value = "Availability rule deleted."; await load() } catch { error.value = "Could not delete this availability rule." } finally { isSaving.value = false } }
onMounted(() => void load())
</script>

<template>
  <section class="availability-surface"><header class="availability-surface__header"><div><p class="availability-surface__eyebrow">Business / Availability</p><h1>Availability</h1></div></header><CollectionToolbar title="Schedule rules" :count="rules.length" :busy="isLoading"><template #actions><AppButton type="button" tone="primary" :disabled="offerings.length === 0" @click="beginCreate">New rule</AppButton></template></CollectionToolbar><AppStatus v-if="feedback" :message="feedback" tone="success" /><AppStatus v-if="isLoading" message="Loading." /><AppStatus v-else-if="error && !form" :message="error" tone="error" retry @retry="load" /><AppStatus v-else-if="rules.length === 0 && !form" message="No availability rules yet." /><div v-else class="availability-surface__workspace"><div class="availability-surface__list"><SurfaceRow v-for="rule in rules" :key="rule.id" :row="{id: String(rule.id), title: rule.businessOfferingTitle, description: `${days[rule.dayOfWeek - 1]} · ${rule.startTimeLocal}–${rule.endTimeLocal}`, badge: rule.active ? 'Active' : 'Inactive', meta: `Capacity ${rule.capacityOverride} · ${rule.slotGranularityMinutes} min`}" :selected="selectedRuleId === rule.id" @click="selectedRuleId = rule.id"><template #actions><AppButton type="button" tone="secondary" @click.stop="beginEdit(rule)">Edit</AppButton><AppButton type="button" tone="danger" @click.stop="remove(rule)">Delete</AppButton></template></SurfaceRow></div><aside v-if="selectedRule" class="availability-surface__preview" aria-label="Availability rule preview"><p class="availability-surface__eyebrow">Selected rule</p><h2>{{ selectedRule.businessOfferingTitle }}</h2><p>{{ days[selectedRule.dayOfWeek - 1] }} · {{ selectedRule.startTimeLocal }}–{{ selectedRule.endTimeLocal }}</p><dl><div><dt>Status</dt><dd>{{ selectedRule.active ? "Active" : "Inactive" }}</dd></div><div><dt>Capacity</dt><dd>{{ selectedRule.capacityOverride }}</dd></div><div><dt>Slot size</dt><dd>{{ selectedRule.slotGranularityMinutes }} min</dd></div><div><dt>Valid from</dt><dd>{{ selectedRule.validFrom }}</dd></div></dl><p class="availability-surface__preview-note">Availability conflicts, capacity, and booking acceptance remain server-validated.</p><div class="availability-surface__preview-actions"><AppButton type="button" tone="secondary" @click="beginEdit(selectedRule)">Edit rule</AppButton><AppButton type="button" tone="danger" @click="remove(selectedRule)">Delete rule</AppButton></div></aside><aside v-else class="availability-surface__preview availability-surface__preview--empty" aria-label="Availability rule preview"><p class="availability-surface__eyebrow">Preview</p><h2>Select a rule</h2><p>Inspect schedule context without leaving the collection.</p></aside></div><AppDialog :open="form !== null" :title="editingId ? 'Edit rule' : 'New rule'" layout="workspace" @close="form = null"><form class="availability-surface__form" @submit.prevent="save"><AppFormField label="Offering" required><select v-model.number="form!.businessOfferingId" required><option v-for="offering in offerings" :key="offering.id" :value="offering.id">{{ offering.title }}</option></select></AppFormField><div class="availability-surface__grid"><AppFormField label="Day"><select v-model.number="form!.dayOfWeek"><option v-for="(day, index) in days" :key="day" :value="index + 1">{{ day }}</option></select></AppFormField><AppFormField label="From" required><input v-model="form!.startTimeLocal" type="time" required></AppFormField><AppFormField label="To" required><input v-model="form!.endTimeLocal" type="time" required></AppFormField></div><div class="availability-surface__grid"><AppFormField label="Slot minutes"><input v-model.number="form!.slotGranularityMinutes" type="number" min="1"></AppFormField><AppFormField label="Capacity"><input v-model.number="form!.capacityOverride" type="number" min="1"></AppFormField><AppFormField label="Valid from" required><input v-model="form!.validFrom" type="date" required></AppFormField></div><label class="availability-surface__toggle"><input v-model="form!.active" type="checkbox"> Active</label><AppStatus v-if="error" :message="error" tone="error" /><AppFormFooter><template #secondary><AppButton type="button" tone="secondary" @click="form = null">Cancel</AppButton></template><template #primary><AppButton type="submit" tone="primary" :loading="isSaving">{{ isSaving ? "Saving" : "Save" }}</AppButton></template></AppFormFooter></form><template #utility><p>The backend evaluates availability, capacity, and booking conflicts. This editor only prepares the permitted schedule rule.</p></template></AppDialog></section>
</template>

<style scoped>
.availability-surface{display:grid;gap:var(--space-3);max-width:none}.availability-surface__header{display:flex;justify-content:space-between;align-items:end;gap:var(--space-3)}.availability-surface__eyebrow{margin:0 0 var(--space-1);color:var(--text-muted);font-size:var(--text-size-label);font-weight:var(--text-weight-semibold);letter-spacing:var(--tracking-label);text-transform:uppercase}h1{margin:0;font-size:clamp(1.55rem,2.5vw,2.3rem);letter-spacing:var(--tracking-tight)}h2{margin:0;font-size:var(--text-size-title)}.availability-surface__list{display:grid;gap:var(--space-1)}.availability-surface__row{display:flex;justify-content:space-between;gap:var(--space-3);align-items:center;padding:var(--space-2) var(--space-3);border:1px solid var(--border-subtle);background:var(--surface-base)}.availability-surface__row>div:first-child{display:grid;gap:var(--space-1)}.availability-surface__row span{color:var(--text-muted);font-size:var(--text-size-meta)}.availability-surface__actions{display:flex;gap:var(--space-1)}.availability-surface button{border:1px solid var(--control-border);border-radius:var(--radius-control);padding:var(--space-1) var(--space-2);background:var(--control-bg);color:var(--control-ink);font:inherit;font-size:var(--text-size-meta);font-weight:var(--text-weight-semibold);cursor:pointer;white-space:nowrap}.availability-surface button:hover{border-color:var(--control-border-active);background:var(--control-bg-hover)}.availability-surface__primary{border-color:var(--accent)!important;background:var(--accent)!important;color:var(--canvas)}.availability-surface__primary:disabled{opacity:.5;cursor:not-allowed}.availability-surface__danger{color:var(--danger)}.availability-surface__secondary{margin-left:var(--space-1)}.availability-surface__form{display:grid;gap:var(--space-3);border:1px solid var(--border-subtle);border-radius:var(--radius-surface);background:var(--surface-base);padding:var(--space-3)}.availability-surface__form label{display:grid;gap:var(--space-1);font-size:var(--text-size-meta);font-weight:var(--text-weight-semibold);color:var(--text-muted)}.availability-surface__form input,.availability-surface__form select{border:1px solid var(--control-border);border-radius:var(--radius-control);padding:var(--space-2);background:var(--control-bg);color:var(--control-ink);font:inherit;font-weight:400}.availability-surface__grid{display:grid;grid-template-columns:repeat(3,1fr);gap:var(--space-2)}.availability-surface__toggle{display:flex!important;align-items:center;gap:var(--space-2)!important}.availability-surface__toggle input{width:auto}.availability-surface__feedback{margin:0;color:var(--success)}.availability-surface__status{padding:var(--space-2) 0;color:var(--text-muted)}.availability-surface__status--error{color:var(--danger)}.availability-surface__status button{margin-left:var(--space-1);border:0;background:transparent;color:inherit;text-decoration:underline}@media(max-width:620px){.availability-surface__row{align-items:start;flex-direction:column}.availability-surface__grid{grid-template-columns:1fr}}
/* Workspace visual remediation keeps schedule rules dense and tokenized. */
.availability-surface{gap:var(--space-3);max-width:none}.availability-surface__list{border-radius:var(--radius-surface)}.availability-surface button,.availability-surface input,.availability-surface select{border-radius:var(--radius-control)}
</style>
<style scoped>
.availability-surface__row { padding: var(--space-2) var(--space-3); background: var(--surface-base); }
.availability-surface__form { border: 1px solid var(--border-subtle); border-radius: var(--radius-surface); background: var(--surface-base); padding: var(--space-3); }
</style>
<style scoped>
