.availability-surface__form select { border-color: var(--control-border); background: var(--control-bg); color: var(--control-ink); }
.availability-surface button:hover { border-color: var(--border-strong); background: var(--surface-hover); }
.availability-surface__primary:hover { border-color: var(--accent) !important; background: var(--accent) !important; color: var(--canvas); }
.availability-surface__danger:hover { background: var(--danger-muted); }
.availability-surface .app-button { border-radius: var(--radius-control); padding: var(--space-1) var(--space-3); background: var(--control-bg); color: var(--control-ink); }
.availability-surface .app-button--primary { border-color: var(--accent); background: var(--accent); color: var(--canvas); }
.availability-surface .app-button--danger { color: var(--danger); }
.availability-surface .app-button:hover:not(:disabled) { border-color: var(--control-border-active); background: var(--control-bg-hover); }
.availability-surface__workspace{display:grid;grid-template-columns:minmax(0,1fr) minmax(16rem,22rem);gap:var(--space-3);align-items:start}.availability-surface__preview{display:grid;gap:var(--space-2);padding:var(--space-3);border:1px solid var(--border-subtle);border-radius:var(--radius-surface);background:var(--surface-raised);color:var(--text-muted)}.availability-surface__preview h2,.availability-surface__preview p{margin:0}.availability-surface__preview h2{color:var(--text);font-size:var(--text-size-title)}.availability-surface__preview dl{display:grid;gap:var(--space-2);margin:var(--space-2) 0}.availability-surface__preview dl div{display:flex;justify-content:space-between;gap:var(--space-2);border-top:1px solid var(--border-subtle);padding-top:var(--space-2)}.availability-surface__preview dt{color:var(--text-soft);font-size:var(--text-size-meta)}.availability-surface__preview dd{margin:0;color:var(--text);font-size:var(--text-size-meta);font-weight:var(--text-weight-semibold)}.availability-surface__preview-note{color:var(--text-soft);font-size:var(--text-size-meta);line-height:1.45}.availability-surface__preview-actions{display:flex;gap:var(--space-2);flex-wrap:wrap}.availability-surface__preview--empty{min-height:10rem;align-content:center}@media(max-width:860px){.availability-surface__workspace{grid-template-columns:1fr}.availability-surface__preview{order:2}}
</style>
